args.command:
$branch_name = "branch-v1.4.0-dev";
$workflow_name = "CI/CD — Dashboard Mictlan (consolidated)";
$job_name = "Deploy Preview (PR)";
$max_retries = 20; # 10 minutes / 30 seconds = 20
$retry_delay = 30; # seconds

for ($i = 0; $i -lt $max_retries; $i++) {
    Write-Host "Polling for workflow run status (attempt $($i + 1)/$max_retries)..."
    $runs_json = gh run list --branch $branch_name --json status,conclusion,name,databaseId,url --limit 5 | ConvertFrom-Json

    $target_run = $runs_json | Where-Object { $_.name -eq $workflow_name } | Select-Object -First 1

    if ($target_run) {
        if ($target_run.status -eq "completed") {
            if ($target_run.conclusion -eq "success") {
                Write-Host "Workflow run completed successfully!"
                $run_id = $target_run.databaseId
                break
            } else {
                Write-Error "Workflow run completed with status $($target_run.conclusion)."
                exit 1
            }
        } else {
            Write-Host "Workflow run status: $($target_run.status). Waiting..."
        }
    } else {
        Write-Host "No matching workflow run found yet. Waiting..."
    }

    Start-Sleep -Seconds $retry_delay
}

if (-not $run_id) {
    Write-Error "Timeout: Workflow run did not complete within the expected time."
    exit 1
}

Write-Host "Extracting job ID for '$job_name'..."
$jobs_json = gh run view $run_id --json jobs | ConvertFrom-Json
$deploy_job = $jobs_json.jobs | Where-Object { $_.name -eq $job_name } | Select-Object -First 1

if (-not $deploy_job) {
    Write-Error "Deploy Preview (PR) job not found in run $run_id."
    exit 1
}

$job_id = $deploy_job.databaseId

Write-Host "Fetching logs for job $job_id to extract preview URL..."
$log_content = gh run view $run_id --job $job_id --log
$preview_url = $log_content | Select-String -Pattern '"url": "\K[^"]*"' | ForEach-Object { $_.Matches.Value }

if ($preview_url) {
    Write-Host "Preview URL: $preview_url"
} else {
    Write-Error "Could not extract preview URL from job logs."
    exit 1
}

