args.command:
$branch_name = "main";
$workflow_name = "CI/CD — Dashboard Mictlan (consolidated)";
$job_name = "Deploy Production";
$prod_project_id = "dashboard-mictlan-prod";
$max_retries = 20;
$retry_delay = 30;

for ($i = 0; $i -lt $max_retries; $i++) {
    Write-Host "Polling for workflow run status (attempt $($i + 1)/$max_retries)..."
    $runs_json = gh run list --branch $branch_name --json status,conclusion,name,databaseId,url --limit 5 | ConvertFrom-Json

    $target_run = $runs_json | Where-Object { $_.name -eq $workflow_name -and $_.status -eq "completed" } | Select-Object -First 1

    if ($target_run) {
        if ($target_run.conclusion -eq "success") {
            Write-Host "Workflow run completed successfully!"
            $run_id = $target_run.databaseId
            break
        } else {
            Write-Error "Workflow run completed with status $($target_run.conclusion)."
            exit 1
        }
    } else {
        $in_progress_run = $runs_json | Where-Object { $_.name -eq $workflow_name -and $_.status -ne "completed" } | Select-Object -First 1
        if ($in_progress_run) {
            Write-Host "Workflow run status: $($in_progress_run.status). Waiting..."
        } else {
            Write-Host "No matching workflow run found yet. Waiting..."
        }
    }

    Start-Sleep -Seconds $retry_delay
}

if (-not $run_id) {
    Write-Error "Timeout: Workflow run did not complete within the expected time."
    exit 1
}

Write-Host "Extracting production URL..."
$sites_json = firebase hosting:sites:list --json --project $prod_project_id | ConvertFrom-Json
$prod_url = $sites_json.result.sites | Where-Object { $_.name -match $prod_project_id } | Select-Object -ExpandProperty defaultUrl -First 1

if ($prod_url) {
    Write-Host "Production URL: $prod_url"
} else {
    Write-Error "Could not extract production URL."
    exit 1
}

